UPDATE board
SET categoryno = #{categoryno}, title = #{title}, content = #{content}, file1saved = #{file1saved}, thumb1 = #{thumb1}, size1 = #{size1}
WHERE boardno = #{boardno}

UPDATE board
SET cnt = cnt + 1
WHERE boardno = #{boardno}

UPDATE board
SET recom = recom + 1
WHERE boardno = #{boardno}

UPDATE board
SET recom = recom - 1
WHERE boardno = #{boardno}

mapper.select:
SELECT COUNT(*) as cnt
FROM board
WHERE boardno=#{boardno}
